import { writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';
import { ACTION } from './action-contract-source.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const outputPath = resolve(__dirname, '..', 'extension', 'wp-actions.js');

const actionEntries = Object.entries(ACTION)
  .map(([key, value]) => `    ${key}: '${value}',`)
  .join('\n');

const output = `// AUTO-GENERATED by watchparty/tools/gen-action-contract.mjs
// Source of truth: watchparty/tools/action-contract-source.mjs
// Do not edit manually - run: node tools/gen-action-contract.mjs

const WPAction = (() => {
  'use strict';

  const ACTION = Object.freeze({
${actionEntries}
  });

  return ACTION;
})();
`;

writeFileSync(outputPath, output, 'utf8');
console.log(`Generated ${outputPath}`);
